{
  "day": "1",
  "heading": "Reach Kathmandu",
  "sub_heading": "",
  "details": "There are direct flights from major cities like New Delhi, Kolkata and Mumbai to Kathmandu (Tribhuvan International Airport-KTM). While cities like Bangalore and Lucknow have connecting flights.\nImportant note: Reach Kathmandu one day before Day 1 because your drive to Ramechhap  starts at 1 AM from Kathmandu the next day. This extra day will give you much needed rest."
}

{
  "day": "2",
  "heading": "Drive to Ramechhap. Fly to Lukla.",
  "sub_heading": "Drive Duration: 6 hrs | Flight Duration: 20-25 mins",
  "details": "Drive to Ramechhap from Kathmandu starts at 1 AM (IST)\nThis transfer and airfare is included in your trek fee."
}

{
  "day": "3",
  "heading": "Trek from Lukla to Phakding.",
  "sub_heading": "Trek Distance: 9 km | Duration: 4-5 hours | Altitude Loss: 9,300 ft to 8,600 ft\nEasy. Gradual descent throughout. You can refill your water bottles at tea houses on the way.",
  "details": ""
}

{
  "day": "4",
  "heading": "Trek from Phakding to Namche Bazaar.",
  "sub_heading": "Trek Distance: 10 km | Duration: 7 hours | Altitude Gain: 8,600 ft to 11,290 ft\nModerate. Initial level walk for 30 minutes followed by an undulating trail for a few hours. Steep climb to Namche hereafter. You can refill your water bottles at tea houses on the way.",
  "details": ""
}

{
  "day": "5",
  "heading": "Acclimatization day at Namche Bazaar",
  "sub_heading": "Today, you’ll do an acclimatisation climb to Everest View Hotel and come back down to Namche Bazaar for lunch.",
  "details": ""
}

{
  "day": "6",
  "heading": "Trek from Namche Bazaar to Tengboche.",
  "sub_heading": "Trek Distance: 9.2 kms | Duration: 4 hours | Altitude Gain: 11,290 ft to 12,687 ft (+ 1397 ft)",
  "details": ""
}

{
  "day": "7",
  "heading": "Trek from Tengboche to Dingboche.",
  "sub_heading": "Trek Distance: 10.8 kms | Duration: 3.5 hours | Altitude Gain: 12,687 ft to 14,469 ft (+ 1782 ft)",
  "details": ""
}

{
  "day": "8",
  "heading": "Acclimatization day at Dingboche.",
  "sub_heading": "",
  "details": ""
}

{
  "day": "9",
  "heading": "Trek from Dingboche to Lobuche.",
  "sub_heading": "Trek Distance: 11.1 kms | Duration: 7 hours | Altitude Gain: 14,469 ft to 16,200 ft (+ 1731 ft)",
  "details": ""
}

{
  "day": "10",
  "heading": "Trek from Labouche to Gorakshep (Excursion to EBC)",
  "sub_heading": "Trek Distance: 8 kms | Duration:3 hours |Altitude Gain: 16,200 ft to 16,900 ft (+ 700 ft)\nModerate. Short, steep ascent followed by 1.5-2 hours of boulder walk. Ends with a gradually ascending trail. Carry sufficient water. You’ll find teahouses on the way to Gorakshep.",
  "details": ""
}

{
  "day": "11",
  "heading": "Climb Kala Pathar. Trek from Gorakshep to Pheriche",
  "sub_heading": "Trek Distance: 15.2 kms | Duration: 3 hours | Altitude Gain and Loss: 16,900 ft to 14,070 ft via 18,200 ft\nDifficult. Gradual descent all the way to Pheriche. Carry sufficient water; you can refill your water bottles at tea houses on the way.",
  "details": ""
}

{
  "day": "12",
  "heading": "Trek from Pheriche to Tengboche.",
  "sub_heading": "Trek Distance: 9 kms | Duration: 4-5 hours | Altitude Loss: 14,070 ft to 12,665 ft\nModerate. 3 km gradual ascent to Tengboche. You can refill your water bottles at tea houses on the way.",
  "details": ""
}

{
  "day": "13",
  "heading": "Trek from Tengboche to Namche Bazaar.",
  "sub_heading": "Trek Distance: 9.2 kms | Duration: 4 hours | Altitude Loss: 12,665 ft to 11,290 ft\nModerate. Continuous descent followed by a final, short stretch of steep ascent. You can refill your water bottles at tea houses on the way.",
  "details": ""
}

{
  "day": "14",
  "heading": "Trek from Namche Bazaar to Lukla.",
  "sub_heading": "Trek Distance: 19 kms | Duration: 7-8 hours | Altitude Loss: 11,290 ft to 9,300 ft\nModerate. Continuous descent to Phakding for a few hours followed by gradual ascent to Lukla. You will find tea houses on the way to refill your water bottles.\nStay the night at Hotel Comfort Inn.",
  "details": ""
}

{
  "day": "15",
  "heading": "Lukla to Kathmandu via Ramechhap",
  "sub_heading": "Take a flight from Lukla to Ramechhap and drive back to Kathmandu. The cost of this transfer is included in your Trek Fee.",
  "details": ""
}
